source("languages/r/brush.R");raw<-list(c(500,520),c(450,450),c(390,395),c(320,370),c(250,370),c(180,390),c(130,450),c(120,520),c(155,585),c(220,635),c(300,650),c(380,620),c(440,570),c(500,520),c(560,465),c(620,410),c(700,370),c(770,380),c(830,420),c(870,480),c(875,545),c(845,610),c(790,660),c(720,675),c(650,655),c(585,610),c(540,560),c(500,520));points<-lapply(raw,function(v)brush_point(v[1],v[2]));stopifnot(build_rounded_drawing_path(list(brush_point(0,0),brush_point(100,0),brush_point(100,100)),40)=="M 0 0 L 55 0 Q 100 0 100 45 L 100 100");args<-commandArgs(trailingOnly=TRUE);input<-if(length(args)>0)args[1]else"assets/example.webp";output<-if(length(args)>1)args[2]else"generated/r.svg";size<-file.info(input)$size;con<-file(input,"rb");bytes<-readBin(con,"raw",n=size);close(con);svg<-render_svg(bytes,"image/webp",1000,1000,points,"🤝 best friends forever",list(magic_gradient=TRUE));dir.create(dirname(output),recursive=TRUE,showWarnings=FALSE);writeLines(svg,output,useBytes=TRUE);cat("Wrote",output,"\n")
